def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        base_score = 0
        if ratio > 3:
            base_score = 3000 + 100 * (ratio - 3) ** 4
        elif ratio > 2:
            base_score = 2000 + 70 * (ratio - 2) ** 3
        elif ratio > 1:
            base_score = 1000 + 30 * (ratio - 1) ** 2 + 5 * np.sin(ratio * 10)
        else:
            if ratio > 0.95:
                base_score = 100 * ratio + 25 + 10 * np.cos(ratio * 15)
            elif ratio > 0.8:
                base_score = 60 * ratio + 20
            elif ratio > 0.5:
                base_score = 30 * ratio + 10
            else:
                base_score = 15 * ratio
            if capacity < 3:
                base_score += 25
            elif 3 <= capacity <= 10:
                base_score += 15
            elif 10 < capacity <= 50:
                base_score += 5
            elif capacity > 150:
                base_score -= 20
        modifier = 1.0
        if i % 4 == 0:
            modifier += 0.2
            if ratio < 0.4:
                modifier += 0.1
            elif ratio > 2.5:
                modifier -= 0.15
        elif i % 4 == 1:
            modifier -= 0.12
            if ratio > 1.7:
                modifier -= 0.07
            elif ratio < 0.6:
                modifier += 0.05
        elif i % 4 == 2:
            modifier += 0.08
            if capacity % 3 == 0:
                modifier += 0.04
                if ratio > 1.2:
                    modifier += 0.03
        else:
            modifier -= 0.05
            if capacity % 5 == 0:
                modifier -= 0.05
                if ratio < 0.3:
                    modifier += 0.02
        adjusted_score = base_score * modifier
        if i % 7 == 0:
            diff_sum = 0
            count = 0
            start = max(0, i - 3)
            end = min(len(bins), i + 4)
            for j in range(start, end):
                if j != i and bins[j] > 0:
                    diff = abs(item - bins[j])
                    diff_sum += diff ** 1.5
                    count += 1
            if count > 0:
                avg_diff = diff_sum / count
                if avg_diff < capacity * 0.3:
                    adjusted_score *= 0.7
                elif avg_diff > capacity * 0.7:
                    adjusted_score *= 1.3
        priorities[i] = adjusted_score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fallback = 10
    else:
        fallback = np.min(finite_priorities)
    for i in range(len(priorities)):
        if not np.isfinite(priorities[i]):
            priorities[i] = fallback + 200
    for i in range(len(priorities)):
        if priorities[i] < 30:
            increment = 15 * (item / (bins[i] + 0.5))
            if i % 2 == 0:
                increment += 5
            else:
                increment += 3
            priorities[i] += increment
    for i in range(len(priorities)):
        if priorities[i] > 2500:
            priorities[i] -= 100
        if i % 6 == 3 and priorities[i] < 100:
            priorities[i] *= 1.1
        if i > 0 and priorities[i-1] < 50 and priorities[i] > 200:
            priorities[i] -= 50
    return priorities
